            {item.InMyCatalog && (
                <div className="bg-green-500 text-white text-[7px] font-black px-1 py-0.5 rounded shadow-lg flex items-center gap-1 uppercase tracking-wider">
                    <CheckCircle2 size={8} /> Visto
                </div>
            )}
